    ~@PlayInputControl()
    {
        UnityEngine.Debug.Assert(!m_gamePlayer.enabled, "This will cause a leak and performance issues, PlayInputControl.gamePlayer.Disable() has not been called.");
        UnityEngine.Debug.Assert(!m_UI.enabled, "This will cause a leak and performance issues, PlayInputControl.UI.Disable() has not been called.");
    }

